import java.time.LocalDateTime;
public class Main {
    public static void main(String[] args) {
        CalendarService svc = new CalendarService();
        svc.createCalendar("alice", "Alice");
        svc.createCalendar("bob", "Bob");
        LocalDateTime t = LocalDateTime.of(2026, 6, 1, 14, 0);
        Event e = new EventBuilder(svc.nextEventId()).title("Review").from(t).to(t.plusHours(1)).organizer("alice").build();
        svc.addEvent("alice", e);
        Invitation inv = svc.inviteUser(e.getId(), "alice", "bob", e);
        svc.acceptInvitation(inv, e);
        if (e.getAttendeeIds().contains("bob") && svc.getCalendar("bob").getEvents().size() == 1) System.out.println("OK_INVITE");
    }
}

